package com.example.sso;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;

import java.io.IOException;

@Controller
@RequestMapping("/logout")
public class LogoutController {

    @GetMapping
    public void logoutGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        doLogoutAndRedirect(request, response);
    }

    @PostMapping
    public void logoutPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        doLogoutAndRedirect(request, response);
    }

    private void doLogoutAndRedirect(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        request.logout();

        response.sendRedirect(request.getParameter("next"));
    }
}